     1→/* ═══════════════════════════════════════════════════
     2→   Profile Post Cards — Parent Container
     3→   ═══════════════════════════════════════════════════ */
     4→.profile-postcards-parent-container {
     5→    position: relative;
     6→    display: flex;
     7→    flex-direction: column;
     8→    justify-content: flex-start;
     9→    align-items: center;
    10→    width: 90%;
    11→    padding: 1.25rem;
    12→    height: fit-content;
    13→    margin-bottom: 1rem;
    14→    margin-top: 1rem;
    15→    border-radius: 18px;
    16→    background-color: var(--bg-glass);
    17→    backdrop-filter: blur(25px);
    18→    -webkit-backdrop-filter: blur(25px);
    19→    border: 0.7px solid var(--bg-glass-border);
    20→    gap: 18px;
    21→}
    22→.profile-postcards-child-container {
    23→    display: flex;
    24→    width: 100%;
    25→    position: relative;
    26→}
    27→.profile-postcards-loading-container {
    28→    display: flex;
    29→    justify-content: center;
    30→    align-items: center;
    31→    width: 90%;
    32→    height: 100vh;
    33→    margin-top: 1rem;
    34→    border-radius: 18px;
    35→    padding: 1rem;
    36→    background-color: var(--bg-glass);
    37→    backdrop-filter: blur(25px);
    38→    -webkit-backdrop-filter: blur(25px);
    39→    border: 0.7px solid var(--bg-glass-border);
    40→    color: var(--text-muted);
    41→    font-family: "Nunito", sans-serif;
    42→    font-weight: 600;
    43→}
    44→
    45→/* ═══════════════════════════════════════════════════
    46→   Individual Profile Card
    47→   ═══════════════════════════════════════════════════ */
    48→.profile-postcards {
    49→    position: relative;
    50→    display: flex;
    51→    flex-direction: column;
    52→    justify-content: flex-start;
    53→    align-items: center;
    54→    width: 100%;
    55→    min-height: fit-content;
    56→    background-color: var(--bg-primary);
    57→    border: 1px solid var(--border-card);
    58→    border-radius: 14px;
    59→    overflow: visible;
    60→    cursor: pointer;
    61→    transition: box-shadow 0.25s ease, border-color 0.25s ease, transform 0.2s ease;
    62→}
    63→.profile-postcards:hover {
    64→    box-shadow: 0 6px 28px rgba(0, 0, 0, 0.07), 0 1px 6px rgba(0, 0, 0, 0.04);
    65→    border-color: rgba(0, 0, 0, 0.09);
    66→    transform: translateY(-1px);
    67→}
    68→[data-theme="dark"] .profile-postcards:hover {
    69→    box-shadow: 0 6px 28px rgba(0, 0, 0, 0.25), 0 1px 6px rgba(0, 0, 0, 0.15);
    70→    border-color: rgba(255, 255, 255, 0.1);
    71→}
    72→.profile-postcards .card-image-banner {
    73→    width: 100%;
    74→    max-height: 240px;
    75→    object-fit: cover;
    76→    display: block;
    77→    border-top-left-radius: 14px;
    78→    border-top-right-radius: 14px;
    79→    transition: opacity 0.2s ease;
    80→}
    81→.profile-postcards:hover .card-image-banner {
    82→    opacity: 0.92;
    83→}
    84→.profile-postcards.is-editing {
    85→    z-index: 500;
    86→    transform: none;
    87→}
    88→.profile-postcards.is-editing:hover {
    89→    transform: none;
    90→    box-shadow: 0 8px 40px rgba(0, 0, 0, 0.2);
    91→    border-color: var(--border-card);
    92→}
    93→
    94→/* ═══════════════════════════════════════════════════
    95→   Card Content Area
    96→   ═══════════════════════════════════════════════════ */
    97→.user-profile-card-content {
    98→    display: flex;
    99→    flex-direction: column;
   100→    gap: 0.5rem;
   101→    width: 100%;
   102→    padding: 1.1rem 1.35rem 0.85rem 1.35rem;
   103→    box-sizing: border-box;
   104→}
   105→.user-profile-card-content .card-icons-container {
   106→    display: flex;
   107→    flex-wrap: wrap;
   108→    width: 100%;
   109→    padding: 0.5rem 0 0 0;
   110→    min-height: 22px;
   111→    align-items: center;
   112→    justify-content: flex-start;
   113→    gap: 0.5rem;
   114→    border-top: 1px solid var(--border-card);
   115→}
   116→.user-profile-card-content .content-container {
   117→    display: flex;
   118→    flex-direction: column;
   119→    justify-content: flex-start;
   120→    align-items: flex-start;
   121→    user-select: none;
   122→    gap: 0.4rem;
   123→}
   124→.user-profile-card-content .feed-text-content-container {
   125→    width: 100%;
   126→}
   127→.user-profile-card-content .user-info-email-container {
   128→    display: none;
   129→}
   130→
   131→/* In-view loader */
   132→.in-view-container {
   133→    display: flex;
   134→    justify-content: center;
   135→    align-items: center;
   136→    width: 100%;
   137→    height: 20px;
   138→    margin-top: 1rem;
   139→}
   140→
   141→/* Avatar rings */
   142→.user-avatar-container.avatar-ring-legend {
   143→    border-radius: 50%;
   144→    border: 2px solid #FFD700;
   145→    box-shadow:
   146→        0 0 6px 1px rgba(255, 215, 0, 0.5),
   147→        0 0 12px 2px rgba(255, 215, 0, 0.35),
   148→        0 0 20px 4px rgba(255, 215, 0, 0.2);
   149→    animation: glow-legend 2s ease-in-out infinite alternate;
   150→}
   151→.user-avatar-container.avatar-ring-og {
   152→    border-radius: 50%;
   153→    border: 2px solid #9B59FF;
   154→    box-shadow:
   155→        0 0 6px 1px rgba(155, 89, 255, 0.5),
   156→        0 0 12px 2px rgba(155, 89, 255, 0.35),
   157→        0 0 20px 4px rgba(155, 89, 255, 0.2);
   158→    animation: glow-og 2s ease-in-out infinite alternate;
   159→}
   160→
   161→@keyframes glow-legend {
   162→    from {
   163→        box-shadow:
   164→            0 0 6px 1px rgba(255, 215, 0, 0.5),
   165→            0 0 12px 2px rgba(255, 215, 0, 0.35),
   166→            0 0 20px 4px rgba(255, 215, 0, 0.2);
   167→    }
   168→    to {
   169→        box-shadow:
   170→            0 0 8px 2px rgba(255, 215, 0, 0.6),
   171→            0 0 16px 4px rgba(255, 215, 0, 0.4),
   172→            0 0 24px 6px rgba(255, 215, 0, 0.25);
   173→    }
   174→}
   175→
   176→@keyframes glow-og {
   177→    from {
   178→        box-shadow:
   179→            0 0 6px 1px rgba(155, 89, 255, 0.5),
   180→            0 0 12px 2px rgba(155, 89, 255, 0.35),
   181→            0 0 20px 4px rgba(155, 89, 255, 0.2);
   182→    }
   183→    to {
   184→        box-shadow:
   185→            0 0 8px 2px rgba(155, 89, 255, 0.6),
   186→            0 0 16px 4px rgba(155, 89, 255, 0.4),
   187→            0 0 24px 6px rgba(155, 89, 255, 0.25);
   188→    }
   189→}
   190→
   191→/* Profile-specific text styles */
