   351→/* ═══════════════════════════════════════════════════
   352→   Delete Confirmation Overlay
   353→   ═══════════════════════════════════════════════════ */
   354→.confirm-delete-container {
   355→    width: 100%;
   356→    height: 100vh;
   357→    position: absolute;
